1708	
1709	void
1710	fz_run_display_list(fz_context *ctx, fz_display_list *list, fz_device *dev, fz_matrix top_ctm, fz_rect scissor, fz_cookie *cookie)
1711	{
1712		fz_display_node *node;
1713		fz_display_node *node_end;
1714		fz_display_node *next_node;
1715		int clipped = 0;
1716		int tiled = 0;
1717		int progress = 0;
1718	
1719		/* Current graphics state as unpacked from list */
1720		fz_path *path = NULL;
1721		float alpha = 1.0f;
1722		fz_matrix ctm = fz_identity;
1723		fz_stroke_state *stroke = NULL;
1724		float color[FZ_MAX_COLORS] = { 0 };
1725		fz_colorspace *colorspace = fz_keep_colorspace(ctx, fz_device_gray(ctx));
1726		fz_color_params color_params;
1727		fz_rect rect = { 0 };
1728	
1729		/* Transformed versions of graphic state entries */
1730		fz_rect trans_rect;
1731		fz_matrix trans_ctm;
1732		int tile_skip_depth = 0;
1733	
1734		if (cookie)
1735		{
1736			cookie->progress_max = list->len;
1737			cookie->progress = 0;
1738		}
1739	
1740		color_params = fz_default_color_params;
1741	
1742		node = list->list;
1743		node_end = &list->list[list->len];
1744		for (; node != node_end ; node = next_node)
1745		{
1746			int empty;
1747			fz_display_node n = *node;
1748			size_t size = n.size;
1749	
1750			if (size == INDIRECT_NODE_THRESHOLD)
1751			{
1752				memcpy(&size, &node[1], sizeof(size_t));
1753				node += SIZE_IN_NODES(sizeof(size_t));
1754				size -= SIZE_IN_NODES(sizeof(size_t));
1755			}
1756	
1757			next_node = node + size;
1758	
1759			/* Check the cookie for aborting */
1760			if (cookie)
1761			{
1762				if (cookie->abort)
1763					break;
1764				cookie->progress = progress;
1765				progress += (int)size;
1766			}
1767	
1768			node++;
1769			if (n.rect)
1770			{
1771				rect = *(fz_rect *)node;
1772				node += SIZE_IN_NODES(sizeof(fz_rect));
1773			}
1774			if (n.cs)
1775			{
1776				int i, en;
1777	
1778				fz_drop_colorspace(ctx, colorspace);
1779				switch (n.cs)
1780				{
1781				default:
1782				case CS_GRAY_0:
1783					colorspace = fz_keep_colorspace(ctx, fz_device_gray(ctx));
1784					color[0] = 0.0f;
1785					break;
1786				case CS_GRAY_1:
1787					colorspace = fz_keep_colorspace(ctx, fz_device_gray(ctx));
1788					color[0] = 1.0f;
1789					break;
1790				case CS_RGB_0:
1791					colorspace = fz_keep_colorspace(ctx, fz_device_rgb(ctx));
1792					color[0] = 0.0f;
1793					color[1] = 0.0f;
1794					color[2] = 0.0f;
1795					break;
1796				case CS_RGB_1:
1797					colorspace = fz_keep_colorspace(ctx, fz_device_rgb(ctx));
1798					color[0] = 1.0f;
1799					color[1] = 1.0f;
1800					color[2] = 1.0f;
1801					break;
1802				case CS_CMYK_0:
1803					colorspace = fz_keep_colorspace(ctx, fz_device_cmyk(ctx));
1804					color[0] = 0.0f;
1805					color[1] = 0.0f;
1806					color[2] = 0.0f;
1807					color[3] = 0.0f;
1808					break;
1809				case CS_CMYK_1:
1810					colorspace = fz_keep_colorspace(ctx, fz_device_cmyk(ctx));
1811					color[0] = 0.0f;
1812					color[1] = 0.0f;
1813					color[2] = 0.0f;
1814					color[3] = 1.0f;
1815					break;
1816				case CS_OTHER_0:
1817					align_node_for_pointer(&node);
1818					colorspace = fz_keep_colorspace(ctx, *(fz_colorspace **)(node));
1819					node += SIZE_IN_NODES(sizeof(fz_colorspace *));
1820					en = fz_colorspace_n(ctx, colorspace);
1821					for (i = 0; i < en; i++)
1822						color[i] = 0.0f;
1823					break;
1824				}
1825			}
1826			if (n.color)
1827			{
1828				int nc = fz_colorspace_n(ctx, colorspace);
1829				memcpy(color, (float *)node, nc * sizeof(float));
1830				node += SIZE_IN_NODES(nc * sizeof(float));
1831			}
1832			if (n.alpha)
1833			{
1834				switch(n.alpha)
1835				{
1836				default:
1837				case ALPHA_0:
1838					alpha = 0.0f;
1839					break;
1840				case ALPHA_1:
1841					alpha = 1.0f;
1842					break;
1843				case ALPHA_PRESENT:
1844					alpha = *(float *)node;
1845					node += SIZE_IN_NODES(sizeof(float));
1846					break;
1847				}
1848			}
1849			if (n.ctm != 0)
1850			{
1851				float *packed_ctm = (float *)node;
1852				if (n.ctm & CTM_CHANGE_AD)
1853				{
1854					ctm.a = *packed_ctm++;
1855					ctm.d = *packed_ctm++;
1856					node += SIZE_IN_NODES(2*sizeof(float));
1857				}
1858				if (n.ctm & CTM_CHANGE_BC)
1859				{
1860					ctm.b = *packed_ctm++;
1861					ctm.c = *packed_ctm++;
1862					node += SIZE_IN_NODES(2*sizeof(float));
1863				}
1864				if (n.ctm & CTM_CHANGE_EF)
1865				{
1866					ctm.e = *packed_ctm++;
1867					ctm.f = *packed_ctm;
1868					node += SIZE_IN_NODES(2*sizeof(float));
1869				}
1870			}
1871			if (n.stroke)
1872			{
1873				align_node_for_pointer(&node);
1874				fz_drop_stroke_state(ctx, stroke);
1875				stroke = fz_keep_stroke_state(ctx, *(fz_stroke_state **)node);
1876				node += SIZE_IN_NODES(sizeof(fz_stroke_state *));
1877			}
1878			if (n.path)
1879			{
1880				align_node_for_pointer(&node);
1881				fz_drop_path(ctx, path);
1882				path = fz_keep_path(ctx, (fz_path *)node);
1883				node += SIZE_IN_NODES(fz_packed_path_size(path));
1884			}
1885	
1886			if (tile_skip_depth > 0)
1887			{
1888				if (n.cmd == FZ_CMD_BEGIN_TILE)
1889					tile_skip_depth++;
1890				else if (n.cmd == FZ_CMD_END_TILE)
1891					tile_skip_depth--;
1892				if (tile_skip_depth > 0)
1893					continue;
1894			}
1895	
1896			trans_rect = fz_transform_rect(rect, top_ctm);
1897	
1898			/* cull objects to draw using a quick visibility test */
1899	
1900			if (tiled ||
1901				n.cmd == FZ_CMD_BEGIN_TILE || n.cmd == FZ_CMD_END_TILE ||
1902				n.cmd == FZ_CMD_RENDER_FLAGS || n.cmd == FZ_CMD_DEFAULT_COLORSPACES ||
1903				n.cmd == FZ_CMD_BEGIN_LAYER || n.cmd == FZ_CMD_END_LAYER ||
1904				n.cmd == FZ_CMD_BEGIN_STRUCTURE || n.cmd == FZ_CMD_END_STRUCTURE ||
1905				n.cmd == FZ_CMD_BEGIN_METATEXT || n.cmd == FZ_CMD_END_METATEXT
1906				)
1907			{
1908				empty = 0;
1909			}
1910			else if (n.cmd == FZ_CMD_FILL_PATH || n.cmd == FZ_CMD_STROKE_PATH)
1911			{
1912				/* Zero area paths are suitable for stroking. */
1913				empty = !fz_is_valid_rect(fz_intersect_rect(trans_rect, scissor));
1914			}
1915			else if (n.cmd == FZ_CMD_FILL_TEXT || n.cmd == FZ_CMD_STROKE_TEXT ||
1916				n.cmd == FZ_CMD_CLIP_TEXT || n.cmd == FZ_CMD_CLIP_STROKE_TEXT)
1917			{
1918				/* Zero area text (such as spaces) should be passed
1919				 * through. Text that is completely outside the scissor
1920				 * can be elided. */
1921				empty = !fz_is_valid_rect(fz_intersect_rect(trans_rect, scissor));
1922			}
1923			else
1924			{
1925				empty = fz_is_empty_rect(fz_intersect_rect(trans_rect, scissor));
1926			}
1927	
1928			/* clipped starts out as 0. It only goes non-zero here if we move inside
1929			 * an 'empty' region. Whenever clipped is non zero, or we are in an empty
1930			 * region, we therefore may need to increment clipped according to the
1931			 * nesting. */
1932			if (clipped || empty)
1933			{
1934				switch (n.cmd)
1935				{
1936				case FZ_CMD_CLIP_PATH:
1937				case FZ_CMD_CLIP_STROKE_PATH:
1938				case FZ_CMD_CLIP_TEXT:
1939				case FZ_CMD_CLIP_STROKE_TEXT:
1940				case FZ_CMD_CLIP_IMAGE_MASK:
1941				case FZ_CMD_BEGIN_MASK:
1942				case FZ_CMD_BEGIN_GROUP:
1943					clipped++;
1944					continue;
1945				case FZ_CMD_BEGIN_STRUCTURE:
1946				case FZ_CMD_END_STRUCTURE:
1947				case FZ_CMD_BEGIN_METATEXT:
1948				case FZ_CMD_END_METATEXT:
1949					/* These may not nest as nicely as we'd like. Just ignore them for
1950					 * the purposes of clipping. */
1951					break;
1952				case FZ_CMD_POP_CLIP:
1953				case FZ_CMD_END_GROUP:
1954					if (!clipped)
1955						goto visible;
1956					clipped--;
1957					continue;
1958				case FZ_CMD_END_MASK:
1959					if (!clipped)
1960						goto visible;
1961					continue;
1962				default:
1963					continue;
1964				}
1965			}
1966	
1967	visible:
1968			trans_ctm = fz_concat(ctm, top_ctm);
1969	
1970			fz_try(ctx)
1971			{
1972				switch (n.cmd)
1973				{
1974				case FZ_CMD_FILL_PATH:
1975					fz_unpack_color_params(&color_params, n.flags);
1976					fz_fill_path(ctx, dev, path, n.flags & 1, trans_ctm, colorspace, color, alpha, color_params);
1977					break;
1978				case FZ_CMD_STROKE_PATH:
1979					fz_unpack_color_params(&color_params, n.flags);
1980					fz_stroke_path(ctx, dev, path, stroke, trans_ctm, colorspace, color, alpha, color_params);
1981					break;
1982				case FZ_CMD_CLIP_PATH:
1983					fz_clip_path(ctx, dev, path, n.flags, trans_ctm, trans_rect);
1984					break;
1985				case FZ_CMD_CLIP_STROKE_PATH:
1986					fz_clip_stroke_path(ctx, dev, path, stroke, trans_ctm, trans_rect);
1987					break;
1988				case FZ_CMD_FILL_TEXT:
1989					fz_unpack_color_params(&color_params, n.flags);
1990					align_node_for_pointer(&node);
1991					fz_fill_text(ctx, dev, *(fz_text **)node, trans_ctm, colorspace, color, alpha, color_params);
1992					break;
1993				case FZ_CMD_STROKE_TEXT:
1994					fz_unpack_color_params(&color_params, n.flags);
1995					align_node_for_pointer(&node);
1996					fz_stroke_text(ctx, dev, *(fz_text **)node, stroke, trans_ctm, colorspace, color, alpha, color_params);
1997					break;
1998				case FZ_CMD_CLIP_TEXT:
1999					align_node_for_pointer(&node);
2000					fz_clip_text(ctx, dev, *(fz_text **)node, trans_ctm, trans_rect);
2001					break;
2002				case FZ_CMD_CLIP_STROKE_TEXT:
2003					align_node_for_pointer(&node);
2004					fz_clip_stroke_text(ctx, dev, *(fz_text **)node, stroke, trans_ctm, trans_rect);
2005					break;
2006				case FZ_CMD_IGNORE_TEXT:
2007					align_node_for_pointer(&node);
2008					fz_ignore_text(ctx, dev, *(fz_text **)node, trans_ctm);
2009					break;
2010				case FZ_CMD_FILL_SHADE:
2011					fz_unpack_color_params(&color_params, n.flags);
2012					align_node_for_pointer(&node);
2013					fz_fill_shade(ctx, dev, *(fz_shade **)node, trans_ctm, alpha, color_params);
2014					break;
2015				case FZ_CMD_FILL_IMAGE:
2016					fz_unpack_color_params(&color_params, n.flags);
2017					align_node_for_pointer(&node);
2018					fz_fill_image(ctx, dev, *(fz_image **)node, trans_ctm, alpha, color_params);
2019					break;
2020				case FZ_CMD_FILL_IMAGE_MASK:
2021					fz_unpack_color_params(&color_params, n.flags);
2022					align_node_for_pointer(&node);
2023					fz_fill_image_mask(ctx, dev, *(fz_image **)node, trans_ctm, colorspace, color, alpha, color_params);
2024					break;
2025				case FZ_CMD_CLIP_IMAGE_MASK:
2026					align_node_for_pointer(&node);
2027					fz_clip_image_mask(ctx, dev, *(fz_image **)node, trans_ctm, trans_rect);
2028					break;
2029				case FZ_CMD_POP_CLIP:
2030					fz_pop_clip(ctx, dev);
2031					break;
2032				case FZ_CMD_BEGIN_MASK:
2033					fz_unpack_color_params(&color_params, n.flags);
2034					fz_begin_mask(ctx, dev, trans_rect, n.flags & 1, colorspace, color, color_params);
2035					break;
2036				case FZ_CMD_END_MASK:
2037					align_node_for_pointer(&node);
2038					fz_end_mask_tr(ctx, dev, *(fz_function **)node);
2039					break;
2040				case FZ_CMD_BEGIN_GROUP:
2041					fz_begin_group(ctx, dev, trans_rect, colorspace, (n.flags & ISOLATED) != 0, (n.flags & KNOCKOUT) != 0, (n.flags>>2), alpha);
2042					break;
2043				case FZ_CMD_END_GROUP:
2044					fz_end_group(ctx, dev);
2045					break;
2046				case FZ_CMD_BEGIN_TILE:
2047				{
2048					int cached;
2049					fz_list_tile_data *data;
2050					fz_rect tile_rect;
2051					data = (fz_list_tile_data *)node;
2052					tiled++;
2053					tile_rect = data->view;
2054					cached = fz_begin_tile_tid(ctx, dev, rect, tile_rect, data->xstep, data->ystep, trans_ctm, data->id, data->doc_id);
2055					if (cached)
2056						tile_skip_depth = 1;
2057					break;
2058				}
2059				case FZ_CMD_END_TILE:
2060					tiled--;
2061					fz_end_tile(ctx, dev);
2062					break;
2063				case FZ_CMD_RENDER_FLAGS:
2064					if (n.flags == 0)
2065						fz_render_flags(ctx, dev, 0, FZ_DEVFLAG_GRIDFIT_AS_TILED);
2066					else if (n.flags == 1)
2067						fz_render_flags(ctx, dev, FZ_DEVFLAG_GRIDFIT_AS_TILED, 0);
2068					break;
2069				case FZ_CMD_DEFAULT_COLORSPACES:
2070					align_node_for_pointer(&node);
2071					fz_set_default_colorspaces(ctx, dev, *(fz_default_colorspaces **)node);
2072					break;
2073				case FZ_CMD_BEGIN_LAYER:
2074					fz_begin_layer(ctx, dev, (const char *)node);
2075					break;
2076				case FZ_CMD_END_LAYER:
2077					fz_end_layer(ctx, dev);
2078					break;
2079				case FZ_CMD_BEGIN_STRUCTURE:
2080				{
2081					const unsigned char *data;
2082					int idx;
2083					data = (const unsigned char *)node;
2084					memcpy(&idx, data+1, sizeof(idx));
2085					fz_begin_structure(ctx, dev, (fz_structure)data[0], (const char *)(&data[1+sizeof(idx)]), idx);
2086					break;
2087				}
2088				case FZ_CMD_END_STRUCTURE:
2089					fz_end_structure(ctx, dev);
2090					break;
2091				case FZ_CMD_BEGIN_METATEXT:
2092				{
2093					const unsigned char *data;
2094					const char *text;
2095					data = (const unsigned char *)node;
2096					text = (const char *)&data[1];
2097					fz_begin_metatext(ctx, dev, (fz_metatext)data[0], text);
2098					break;
2099				}
2100				case FZ_CMD_END_METATEXT:
2101					fz_end_metatext(ctx, dev);
2102					break;
2103				}
2104			}
2105			fz_catch(ctx)
2106			{
2107				if (fz_caught(ctx) == FZ_ERROR_SYSTEM)
2108				{
2109					fz_drop_colorspace(ctx, colorspace);
2110					fz_drop_stroke_state(ctx, stroke);
2111					fz_drop_path(ctx, path);
2112					fz_rethrow(ctx);
2113				}
2114				/* Swallow the error */
2115				if (cookie)
2116					cookie->errors++;
2117				if (fz_caught(ctx) == FZ_ERROR_ABORT)
2118				{
2119					fz_ignore_error(ctx);
2120					break;
2121				}
2122				fz_report_error(ctx);
2123				fz_warn(ctx, "Ignoring error during interpretation");
2124			}
2125		}
2126		fz_drop_colorspace(ctx, colorspace);
2127		fz_drop_stroke_state(ctx, stroke);
2128		fz_drop_path(ctx, path);
2129		if (cookie)
2130			cookie->progress = progress;
2131	}
2132

