/* 示例代码：record-once-play-many.c
 * 把一页录制进显示列表，再以 100% / 200% / 400% 回放到 PNG，验证“一次录制多次渲染”。 */
#include <mupdf/fitz.h>
#include <stdio.h>
#include <time.h>

int main(int argc, char **argv)
{
    const char *filename = argc >= 2 ? argv[1] : "input.pdf";
    int pageno = argc >= 3 ? atoi(argv[2]) : 1;   /* 用户页码，从 1 起 */
    float scales[] = { 1.0f, 2.0f, 4.0f };
    int i;

    fz_context *ctx = fz_new_context(NULL, NULL, FZ_STORE_DEFAULT);
    fz_register_document_handlers(ctx);

    fz_document *doc = NULL;
    fz_page *page = NULL;
    fz_display_list *list = NULL;
    fz_device *dev = NULL;

    fz_var(doc); fz_var(page); fz_var(list); fz_var(dev);

    fz_try(ctx)
    {
        doc = fz_open_document(ctx, filename);
        page = fz_load_page(ctx, doc, pageno - 1);
        fz_rect mediabox = fz_bound_page(ctx, page);

        /* ① 录制：创建空列表 + list device + 跑页面 */
        list = fz_new_display_list(ctx, mediabox);
        dev = fz_new_list_device(ctx, list);
        fz_run_page(ctx, page, dev, fz_identity, NULL);
        fz_close_device(ctx, dev);
        fz_drop_device(ctx, dev); dev = NULL;

        /* 页面内容已全部进入列表，页面对象不再需要 */
        fz_drop_page(ctx, page); page = NULL;

        /* ② 回放：用同一个列表，分别以三种缩放渲染到 pixmap 并保存 PNG */
        for (i = 0; i < 3; i++)
        {
            fz_matrix ctm = fz_scale(scales[i], scales[i]);
            fz_pixmap *pix = fz_new_pixmap_from_display_list(ctx, list, ctm, fz_device_rgb(ctx), 0, NULL);
            char out[64];
            snprintf(out, sizeof out, "scale_%d.png", (int)(scales[i] * 100));
            fz_save_pixmap_as_png(ctx, pix, out);
            fz_drop_pixmap(ctx, pix);
            printf("wrote %s (%dx%d)\n", out, fz_pixmap_width(ctx, pix), fz_pixmap_height(ctx, pix));
        }
    }
    fz_always(ctx)
    {
        fz_drop_device(ctx, dev);
        fz_drop_display_list(ctx, list);
        fz_drop_page(ctx, page);
        fz_drop_document(ctx, doc);
    }
    fz_catch(ctx)
    {
        fz_report_error(ctx);
        fz_drop_context(ctx);
        return 1;
    }

    fz_drop_context(ctx);
    return 0;
}
